// Extract the text from the Slack event payload
// Adjust field paths if using native Slack trigger vs webhook
const body = $input.first().json.body || $input.first().json;
const text = body.event?.text || body.text || body.raw_input || 'No input found';
const channel = body.event?.channel || body.channel || 'unknown';
const user = body.event?.user || body.user || 'unknown';

return [{
  json: {
    raw_input: text,
    channel,
    user,
    timestamp: new Date().toISOString()
  }
}];

// Parse and validate the agent response
const raw = $input.first().json;

// Handle both direct JSON response and nested response.body
let brief;
try {
  brief = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch(e) {
  return [{ json: { error: 'Failed to parse agent response', raw } }];
}

// Validate required fields
const required = ['problem', 'affected', 'metrics', 'assumption'];
const missing = required.filter(k => !brief[k]);
if (missing.length > 0) {
  return [{ json: { error: `Missing fields: ${missing.join(', ')}`, brief } }];
}

// Format for downstream nodes
return [{
  json: {
    ...brief,
    metrics_formatted: Array.isArray(brief.metrics) 
      ? brief.metrics.join('\n• ') 
      : brief.metrics,
    is_valid: true
  }
}];

